valid.code:
const str = 'John Smith';

/* ✓ GOOD */
var newStr = str.replace(/(\w+)\s(\w+)/, '$2, $1');
// newStr = 'Smith, John'
var newStr = str.replace(/(?<first>\w+)\s(?<last>\w+)/, '$<last>, $<first>');
// newStr = 'Smith, John'

const str = 'John Smith';

var newStr = str.replace(/(\w+)\s(\w+)/, '$$3, $1 $2');
var newStr = str.replace(/(?<first>\w+)\s(?<last>\w+)/, '$<last>, $<first> $$<middle>');

